-- Connect to Redis with connection pooling
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil, err
    end

    if REDIS_PASSWORD then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            ngx.log(ngx.ERR, "Failed to authenticate with Redis: ", err)
            return nil, err
        end
    end

    return red
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Validate plugin code for basic safety checks
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size (64KB)"
    end

    -- Block dangerous patterns
    local blocked_patterns = {
        "os%s*%.",
        "io%s*%.",
        "dofile",
        "loadfile",
        "require%s*%(",
        "rawset",
        "rawget",
        "rawequal",
        "rawlen",
        "setmetatable",
        "getmetatable",
        "setfenv",
        "getfenv",
        "debug%s*%.",
        "package%s*%.",
        "collectgarbage",
        "coroutine%s*%.",
        "module%s*%(",
        "ngx%.location",
        "ngx%.exec",
        "ngx%.redirect",
    }

    for _, pattern in ipairs(blocked_patterns) do
        if code:find(pattern) then
            return false, "Plugin code contains blocked pattern: " .. pattern
        end
    end

    return true, nil
end

-- Compile and cache plugin code
local function compile_plugin(plugin_name, code, request_ctx)
    -- Validate the code
    local valid, err = validate_plugin_code(code)
    if not valid then
        return nil, "Validation failed for plugin '" .. plugin_name .. "': " .. err
    end

    -- Wrap the code to return a plugin table with lifecycle hooks
    local wrapped_code = string.format([[
        local plugin = {}
        -- Plugin code begins
        %s
        -- Plugin code ends
        return plugin
    ]], code)

    -- Use load() (Lua 5.1 loadstring fallback)
    local load_fn = load or loadstring
    local chunk, compile_err = load_fn(wrapped_code, "plugin:" .. plugin_name)
    if not chunk then
        return nil, "Compilation failed for plugin '" .. plugin_name .. "': " .. compile_err
    end

    -- Apply sandbox environment
    local sandbox = create_sandbox_env(request_ctx)
    if setfenv then
        -- Lua 5.1
        setfenv(chunk, sandbox)
    else
        -- Lua 5.2+ - load() already supports env parameter
        chunk, compile_err = load(wrapped_code, "plugin:" .. plugin_name, "t", sandbox)
        if not chunk then
            return nil, "Compilation failed for plugin '" .. plugin_name .. "': " .. compile_err
        end
    end

    return chunk, nil
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    -- Check local cache first
    local cached_code = plugin_cache and plugin_cache:get(plugin_name)
    if cached_code then
        ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
        return cached_code, nil
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    -- Load the plugin code
    local code, redis_err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name)
    if not code or code == ngx.null then
        release_redis_connection(red)
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Optionally load plugin metadata
    local meta_raw = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    local meta = nil
    if meta_raw and meta_raw ~= ngx.null then
        meta = cjson.decode(meta_raw)
    end

    release_redis_connection(red)

    -- Cache the code
    if plugin_cache then
        local ok, cache_err = plugin_cache:set(plugin_name, code, PLUGIN_CACHE_TTL)
        if not ok then
            ngx.log(ngx.WARN, "Failed to cache plugin '", plugin_name, "': ", cache_err)
        end
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' loaded from Redis",
        meta and (" (v" .. (meta.version or "unknown") .. ")") or "")

    return code, nil, meta
end

-- Load plugin code from HTTP header
local function load_plugin_from_header()
    local headers = ngx.req.get_headers()

    -- Support base64-encoded plugin code in header
    local plugin_code_b64 = headers["X-Gateway-Plugin-Code"]
    local plugin_code_raw = headers["X-Gateway-Plugin-Code-Raw"]
    local plugin_name = headers["X-Gateway-Plugin-Name"] or "inline-header-plugin"

    local code = nil

    if plugin_code_b64 then
        code = ngx.decode_base64(plugin_code_b64)
        if not code then
            return nil, nil, "Failed to decode base64 plugin code from header"
        end
    elseif plugin_code_raw then
        code = plugin_code_raw
    end

    if code then
        return code, plugin_name, nil
    end

    return nil, nil, nil
end

-- Execute a plugin with lifecycle hooks
local function execute_plugin(plugin_name, code, phase, request_ctx)
    local chunk, err = compile_plugin(plugin_name, code, request_ctx)
    if not chunk then
        return false, err
    end

    -- Execute the chunk to get the plugin table
    local ok, plugin_or_err = pcall(chunk)
    if not ok then
        return false, "Runtime error loading plugin '" .. plugin_name .. "': " .. tostring(plugin_or_err)
    end

    local plugin = plugin_or_err

    -- Support both table-based plugins and simple function plugins
    if type(plugin) == "function" then
        local exec_ok, exec_err = pcall(plugin, request_ctx)
        if not exec_ok then
            return false, "Execution error in plugin '" .. plugin_name .. "': " .. tostring(exec_err)
        end
        return true, nil
    end

    if type(plugin) ~= "table" then
        return false, "Plugin '" .. plugin_name .. "' must return a table or function"
    end

    -- Execute the appropriate phase handler
    local phase_handler = plugin[phase]
    if phase_handler and type(phase_handler) == "function" then
        local exec_ok, exec_result = pcall(phase_handler, request_ctx)
        if not exec_ok then
            return false, "Error in plugin '" .. plugin_name .. "' phase '" .. phase .. "': " .. tostring(exec_result)
        end
        return true, exec_result
    end

    -- Fallback: try "handler" or "run" as generic entry points
    local generic_handler = plugin.handler or plugin.run or plugin.execute
    if generic_handler and type(generic_handler) == "function" then
        local exec_ok, exec_result = pcall(generic_handler, phase, request_ctx)
        if not exec_ok then
            return false, "Error in plugin '" .. plugin_name .. "' handler: " .. tostring(exec_result)
        end
        return true, exec_result
    end

    ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' has no handler for phase '", phase, "'")
    return true, nil
end

-- Store a plugin in Redis
local function store_plugin_in_redis(plugin_name, code, metadata)
    local valid, err = validate_plugin_code(code)
    if not valid then
        return false, err
    end

    local red, redis_err = get_redis_connection()
    if not red then
        return false, "Redis connection failed: " .. (redis_err or "unknown")
    end

    -- Store the code
    local ok, store_err = red:set(REDIS_PLUGIN_PREFIX .. plugin_name, code)
    if not ok then
        release_redis_connection(red)
        return false, "Failed to store plugin: " .. (store_err or "unknown")
    end

    -- Store metadata if provided
    if metadata then
        metadata.updated_at = ngx.now()
        metadata.name = plugin_name
        local meta_json = cjson.encode(metadata)
        red:set(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta", meta_json)
    end

    release_redis_connection(red)

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete(plugin_name)
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' stored in Redis")
    return true, nil
end

-- Delete a plugin from Redis
local function delete_plugin_from_redis(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return false, "Redis connection failed: " .. (err or "unknown")
    end

    red:del(REDIS_PLUGIN_PREFIX .. plugin_name)
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")

    release_redis_connection(red)

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete(plugin_name)
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' deleted from Redis")
    return true, nil
end

-- List all plugins in Redis
local function list_plugins_from_redis()
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local keys, scan_err = red:keys(REDIS_PLUGIN_PREFIX .. "*")
    if not keys then
        release_redis_connection(red)
        return nil, "Failed to list plugins: " .. (scan_err or "unknown")
    end

    local plugins = {}
    for _, key in ipairs(keys) do
        -- Only list main plugin keys, not metadata keys
        if not key:find(":meta$") then
            local name = key:gsub("^" .. REDIS_PLUGIN_PREFIX, "")
            local meta_raw = red:get(key .. ":meta")
            local meta = nil
            if meta_raw and meta_raw ~= ngx.null then
                meta = cjson.decode(meta_raw)
            end
            table.insert(plugins, {
                name = name,
                meta = meta,
            })
        end
    end

    release_redis_connection(red)
    return plugins, nil
end

-- Invalidate plugin cache
local function invalidate_cache(plugin_name)
    if plugin_cache then
        if plugin_name then
            plugin_cache:delete(plugin_name)
            ngx.log(ngx.INFO, "Cache invalidated for plugin '", plugin_name, "'")
        else
            plugin_cache:flush_all()
            ngx.log(ngx.INFO, "Entire plugin cache flushed")
        end
    end
    return true
end

-- Main gateway handler: processes plugins for a request
local function gateway_handler()
    local uri = ngx.var.uri
    local method = ngx.req.get_method()

    -- Admin API for plugin management
    if uri:find("^/__gateway/plugins") then
        return handle_admin_api(method, uri)
    end

    -- Build request context
    local request_ctx = {
        uri = uri,
        method = method,
        headers = ngx.req.get_headers(),
        args = ngx.req.get_uri_args(),
        remote_addr = ngx.var.remote_addr,
        start_time = ngx.now(),
        plugin_data = {},
    }

    -- Determine current phase
    local phase = ngx.get_phase()
    if phase == "rewrite" then
        phase = "rewrite"
    elseif phase == "access" then
        phase = "access"
    elseif phase == "content" then
        phase = "content"
    elseif phase == "header_filter" then
        phase = "header_filter"
    elseif phase == "body_filter" then
        phase = "body_filter"
    elseif phase == "log" then
        phase = "log"
    end

    -- 1. Check for inline plugin code from HTTP header
    local header_code, header_plugin_name, header_err = load_plugin_from_header()
    if header_err then
        ngx.log(ngx.ERR, "Error loading header plugin: ", header_err)
    end

    if header_code then
        -- Only allow header plugins if explicitly enabled (security consideration)
        local allow_header_plugins = os.getenv("GATEWAY_ALLOW_HEADER_PLUGINS")
        if allow_header_plugins == "true" then
            local ok, exec_err = execute_plugin(header_plugin_name, header_code, phase, request_ctx)
            if not ok then
                ngx.log(ngx.ERR, "Header plugin execution error: ", exec_err)
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({
                    error = "Plugin execution error",
                    message = exec_err,
                }))
                return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
            end
        else
            ngx.log(ngx.WARN, "Header plugin rejected: feature not enabled")
        end
    end

    -- 2. Load and execute plugins configured in Redis for this route
    local red, redis_err = get_redis_connection()
    if red then
        -- Get the plugin chain for this route
        local route_key = "gateway:route:" .. method .. ":" .. uri .. ":plugins"
        local plugin_list_raw, _ = red:get(route_key)

        -- Fallback to a global plugin chain
        if not plugin_list_raw or plugin_list_raw == ngx.null then
            plugin_list_raw, _ = red:get("gateway:global:plugins")
        end

        release_redis_connection(red)

        if plugin_list_raw and plugin_list_raw ~= ngx.null then
            local plugin_list = cjson.decode(plugin_list_raw)
            if plugin_list and type(plugin_list) == "table" then
                for i, plugin_config in ipairs(plugin_list) do
                    local pname = type(plugin_config) == "string" and plugin_config or plugin_config.name
                    local penabled = type(plugin_config) == "table" and plugin_config.enabled ~= false or true

                    if pname and penabled then
                        local code, load_err = load_plugin_from_redis(pname)
                        if code then
                            -- Pass plugin-specific config in context
                            if type(plugin_config) == "table" and plugin_config.config then
                                request_ctx.plugin_config = plugin_config.config
                            else
                                request_ctx.plugin_config = {}
                            end

                            local ok, exec_result = execute_plugin(pname, code, phase, request_ctx)
                            if not ok then
                                ngx.log(ngx.ERR, "Plugin '", pname, "' execution error: ", exec_result)
                                -- Continue with next plugin or halt based on config
                                if type(plugin_config) == "table" and plugin_config.halt_on_error then
                                    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                                    ngx.say(cjson.encode({
                                        error = "Plugin error",
                                        plugin = pname,
                                        message = exec_result,
                                    }))
                                    return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
                                end
                            end

                            -- Check if plugin wants to halt the chain
                            if exec_result == "halt" or (request_ctx.plugin_data and request_ctx.plugin_data._halt) then
                                ngx.log(ngx.INFO, "Plugin chain halted by '", pname, "'")
                                break
                            end
                        else
                            ngx.log(ngx.WARN, "Failed to load plugin '", pname, "': ", load_err)
                        end
                    end
                end
            end
        end
    else
        ngx.log(ngx.WARN, "Could not connect to Redis for plugin loading: ", redis_err)
    end

    -- Store context for downstream phases
    ngx.ctx.gateway_ctx = request_ctx
end

-- Admin API handler for plugin CRUD operations
function handle_admin_api(method, uri)
    -- Simple API key auth for admin endpoints
    local admin_key = ngx.req.get_headers()["X-Gateway-Admin-Key"]
    local expected_key = os.getenv("GATEWAY_ADMIN_KEY") or "changeme"

    if admin_key ~= expected_key then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Unauthorized" }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    ngx.header["Content-Type"] = "application/json"

    -- GET /__gateway/plugins - List all plugins
    if method == "GET" and uri == "/__gateway/plugins" then
        local plugins, err = list_plugins_from_redis()
        if not plugins then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end
        ngx.say(cjson.encode({ plugins = plugins }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- Extract plugin name from URL: /__gateway/plugins/{name}
    local plugin_name = uri:match("^/__gateway/plugins/([%w_-]+)$")

    -- GET /__gateway/plugins/{name} - Get a specific plugin
    if method == "GET" and plugin_name then
        local code, err = load_plugin_from_redis(plugin_name)
        if not code then
            ngx.status = ngx.HTTP_NOT_FOUND
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_NOT_FOUND)
        end
        ngx.say(cjson.encode({
            name = plugin_name,
            code = code,
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- PUT /__gateway/plugins/{name} - Create or update a plugin
    if (method == "PUT" or method == "POST") and plugin_name then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Request body required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local payload = cjson.decode(body)
        if not payload or not payload.code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "JSON body with 'code' field required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local metadata = payload.metadata or {
            version = payload.version or "1.0.0",
            description = payload.description or "",
            author = payload.author or "unknown",
        }

        local ok, err = store_plugin_in_redis(plugin_name, payload.code, metadata)
        if not ok then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        ngx.status = 201
        ngx.say(cjson.encode({
            message = "Plugin '" .. plugin_name .. "' stored successfully",
            name = plugin_name,
        }))
        return ngx.exit(201)
    end

    -- DELETE /__gateway/plugins/{name} - Delete a plugin
    if method == "DELETE" and plugin_name then
        local ok, err = delete_plugin_from_redis(plugin_name)
        if not ok then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end
        ngx.say(cjson.encode({
            message = "Plugin '" .. plugin_name .. "' deleted successfully",
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- POST /__gateway/plugins/{name}/test - Test execute a plugin
    local test_plugin_name = uri:match("^/__gateway/plugins/([%w_-]+)/test$")
    if method == "POST" and test_plugin_name then
        local code, err = load_plugin_from_redis(test_plugin_name)
        if not code then
            ngx.status = ngx.HTTP_NOT_FOUND
            ngx.say(cjson.encode({ error = err }))
            return ngx.exit(ngx.HTTP_NOT_FOUND)
        end

        local test_ctx = {
            uri = "/test",
            method = "GET",
            headers = {},
            args = {},
            remote_addr = "127.0.0.1",
            start_time = ngx.now(),
            plugin_data = {},
            plugin_config = {},
            _test_mode = true,
        }

        local ok, result = execute_plugin(test_plugin_name, code, "access", test_ctx)
        ngx.say(cjson.encode({
            success = ok,
            result = result,
            context = test_ctx.plugin_data,
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- POST /__gateway/cache/invalidate - Invalidate plugin cache
    if method == "POST" and uri == "/__gateway/cache/invalidate" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        local target_plugin = nil
        if body then
            local payload = cjson.decode(body)
            if payload then
                target_plugin = payload.plugin_name
            end
        end
        invalidate_cache(target_plugin)
        ngx.say(cjson.encode({
            message = target_plugin and ("Cache invalidated for '" .. target_plugin .. "'") or "Entire cache flushed",
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    -- POST /__gateway/plugins/execute-inline - Execute inline plugin code
    if method == "POST" and uri == "/__gateway/plugins/execute-inline" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Request body required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local payload = cjson.decode(body)
        if not payload or not payload.code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "JSON body with 'code' field required" }))
            return ngx.exit(ngx.HTTP_BAD_REQUEST)
        end

        local exec_ctx = {
            uri = ngx.var.uri,
            method = method,
            headers = ngx.req.get_headers(),
            args = ngx.req.get_uri_args(),
            remote_addr = ngx.var.remote_addr,
            start_time = ngx.now(),
            plugin_data = {},
            plugin_config = payload.config or {},
        }

        local ok, result = execute_plugin(
            payload.name or "inline-execute",
            payload.code,
            payload.phase or "access",
            exec_ctx
        )

        ngx.say(cjson.encode({
            success = ok,
            result = result,
            context = exec_ctx.plugin_data,
        }))
        return ngx.exit(ngx.HTTP_OK)
    end

    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say(cjson.encode({ error = "Unknown admin endpoint" }))
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

-- Module exports
local _M = {
    _VERSION = "1.0.0",
    gateway_handler = gateway_handler,
    handle_admin_api = handle_admin_api,
    load_plugin_from_redis = load_plugin_from_redis,
    load_plugin_from_header = load_plugin_from_header,
    store_plugin_in_redis = store_plugin_in_redis,
    delete_plugin_from_redis = delete_plugin_from_redis,
    list_plugins_from_redis = list_plugins_from_redis,
    execute_plugin = execute_plugin,
    compile_plugin = compile_plugin,
    validate_plugin_code = validate_plugin_code,
    invalidate_cache = invalidate_cache,
    create_sandbox_env = create_sandbox_env,
}

-- Auto-execute if called directly from nginx config
-- Usage in nginx.conf:
--   lua_shared_dict plugin_cache 10m;
--   content_by_lua_file /path/to/gateway_plugins.lua;
if ngx.get_phase() == "content" or ngx.get_phase() == "access" or ngx.get_phase() == "rewrite" then
    gateway_handler()
end

return _M